/*
 * Validate flash address and length to prevent out-of-bounds access.
 */
static bool validate_flash_params(uint32_t address, size_t len)
{
    if (len == 0 || len > MAX_FLASH_DATA_LEN) {
        return false;
    }

    /* Check the address is within our simulated flash region */
    if (address < FLASH_REGION_START) {
        return false;
    }

    uint32_t offset = address - FLASH_REGION_START;
    if (offset >= FLASH_SIM_SIZE) {
        return false;
    }

    /* Check for overflow */
    if (offset + len > FLASH_SIM_SIZE) {
        return false;
    }

    return true;
}

/*
 * Write to flash memory. Strictly admin-only operation.
 * Validates all parameters before writing.
 */
static int flash_write(const struct task_identity *identity,
                       uint32_t address, const uint8_t *data, size_t len)
{
    /* Enforce admin privilege */
    if (!check_privilege(identity, PRIV_ADMIN, OP_WRITE_FLASH)) {
        return -EACCES;
    }

    /* Validate parameters */
    if (!data) {
        return -EINVAL;
    }

    if (!validate_flash_params(address, len)) {
        audit_log_event(identity->thread_id, identity->privilege_level,
                       OP_WRITE_FLASH, false, "Invalid flash parameters");
        return -EINVAL;
    }

    /* Check write protection config */
    k_mutex_lock(&config_mutex, K_FOREVER);
    struct config_entry *wp_entry = find_config_entry("flash.write_protect");
    if (wp_entry && strncmp(wp_entry->value, "true", 4) == 0) {
        k_mutex_unlock(&config_mutex);
        audit_log_event(identity->thread_id, identity->privilege_level,
                       OP_WRITE_FLASH, false, "Flash is write-protected");
        return -EACCES;
    }
    k_mutex_unlock(&config_mutex);

    /* Perform the write */
    uint32_t offset = address - FLASH_REGION_START;
    memcpy(&simulated_flash[offset], data, len);

    char detail[64];
    snprintk(detail, sizeof(detail), "Flash write at 0x%08x, %zu bytes",
             address, len);
    audit_log_event(identity->thread_id, identity->privilege_level,
                   OP_WRITE_FLASH, true, detail);

    printk("[FLASH] Written %zu bytes at address 0x%08x\n", len, address);
    return 0;
}

/* ============================================================
 * Request Validation
 * ============================================================ */

/*
 * Validate a privilege request before processing.
 * Checks for:
 * - Valid operation type
 * - Proper requester identification
 * - Input sanitization
 */
static bool validate_request(const struct privilege_request *req)
{
    if (!req) {
        return false;
    }

    /* Validate operation type */
    if (req->operation != OP_WRITE_FLASH &&
        req->operation != OP_MODIFY_CONFIG &&
        req->operation != OP_READ_CONFIG) {
        printk("[SECURITY] Invalid operation type: %d\n", req->operation);
        return false;
    }

    /* Validate requester has at least user privilege */
    if (req->requester_priv < PRIV_USER) {
        printk("[SECURITY] Requester has no privilege\n");
        return false;
    }

    /* Validate requester identity exists */
    if (req->requester_id == NULL) {
        printk("[SECURITY] Null requester ID\n");
        return false;
    }

    /* Validate the requester token matches the known user identity */
    if (req->requester_id == user_identity.thread_id) {
        uint32_t expected = generate_token(user_identity.thread_id,
                                            user_identity.privilege_level);
        if (req->requester_token != expected) {
            printk("[SECURITY] Requester token mismatch\n");
            return false;
        }
    } else {
        printk("[SECURITY] Unknown requester thread\n");
        return false;
    }

    /* Validate string fields are null-terminated */
    if (req->operation == OP_MODIFY_CONFIG || req->operation == OP_READ_CONFIG) {
        bool key_terminated = false;
        for (size_t i = 0; i < MAX_KEY_LEN; i++) {
            if (req->key[i] == '\0') {
                key_terminated = true;
                break;
            }
        }
        if (!key_terminated) {
            printk("[SECURITY] Key not null-terminated\n");
            return false;
        }
    }

    /* Validate flash parameters if flash operation */
    if (req->operation == OP_WRITE_FLASH) {
        if (!validate_flash_params(req->flash_address, req->flash_data_len)) {
            printk("[SECURITY] Invalid flash parameters in request\n");
            return false;
        }
    }

    return true;
}

/* ============================================================
 * Admin Task - Processes privileged requests
 * ============================================================ */

static void admin_task(void *p1, void *p2, void *p3)
{
    ARG_UNUSED(p1);
    ARG_UNUSED(p2);
    ARG_UNUSED(p3);

    printk("[ADMIN] Admin task started (tid=%p, priv=%d)\n",
           admin_identity.thread_id, admin_identity.privilege_level);

    while (1) {
        /* Wait for a request from user task */
        k_sem_take(&request_sem, K_FOREVER);

        printk("[ADMIN] Processing request: op=%d from tid=%p\n",
               pending_request.operation, pending_request.requester_id);

        /* Step 1: Validate the request thoroughly */
        if (!validate_request(&pending_request)) {
            printk("[ADMIN] Request validation FAILED\n");
            pending_request.result_code = -EINVAL;
            pending_request.status = REQ_STATUS_DENIED;
            k_sem_give(&response_sem);
            continue;
        }

        /* Step 2: Verify OUR identity before performing privileged ops */
        if (!verify_identity(&admin_identity)) {
            printk("[ADMIN] CRITICAL: Admin identity verification failed!\n");
            pending_request.result_code = -EFAULT;
            pending_request.status = REQ_STATUS_DENIED;
            k_sem_give(&response_sem);
            continue;
        }

        int result = -ENOTSUP;

        /* Step 3: Process the request using admin's verified identity */
        switch (pending_request.operation) {
        case OP_WRITE_FLASH:
            printk("[ADMIN] Executing flash write on behalf of user\n");
            result = flash_write(&admin_identity,
                                pending_request.flash_address,
                                pending_request.flash_data,
                                pending_request.flash_data_len);
            break;

        case OP_MODIFY_CONFIG:
            printk("[ADMIN] Executing config modify on behalf of user\n");
            result = config_write(&admin_identity,
                                 pending_request.key,
                                 pending_request.value);
            break;

        default:
            printk("[ADMIN] Unsupported operation: %d\n",
                   pending_request.operation);
            result = -ENOTSUP;
            break;
        }

        pending_request.result_code = result;
        pending_request.status = (result == 0) ?
                                 REQ_STATUS_COMPLETED : REQ_STATUS_DENIED;

        printk("[ADMIN] Request completed with result: %d\n", result);

        /* Signal the user task that the response is ready */
        k_sem_give(&response_sem);
    }
}

/* ============================================================
 * User Request API - Submit requests to admin
 * ============================================================ */

/*
 * Submit a privileged request to the admin task.
 * The user task CANNOT perform these operations directly.
 * Instead, it must go through this controlled channel.
 */
static int submit_privileged_request(const struct task_identity *identity,
                                     struct privilege_request *req)
{
    /* Verify the caller is who they say they are */
    if (!verify_identity(identity)) {
        printk("[USER] Identity verification failed, cannot submit request\n");
        return -EACCES;
    }

    /* Fill in requester information from verified identity */
    req->requester_id = identity->thread_id;
    req->requester_priv = identity->privilege_level;
    req->requester_token = identity->auth_token;
    req->status = REQ_STATUS_PENDING;
    req->result_code = 0;

    /* Copy request to shared buffer (protected by semaphore flow) */
    memcpy(&pending_request, req, sizeof(struct privilege_request));

    /* Signal admin task */
    k_sem_give(&request_sem);

    /* Wait for response */
    k_sem_take(&response_sem, K_FOREVER);

    return pending_request.result_code;
}

